const express = require('express');
const axios = require('axios');
const path = require('path');

const app = express();
const PORT = process.env.PORT || 3000;

app.use(express.json());
app.use(express.static(path.join(__dirname, 'public')));
app.use('/node_modules', express.static(path.join(__dirname, 'node_modules')));

app.post('/api/verify-phone', async (req, res) => {
    const { phoneNumber } = req.body;

    if (!phoneNumber) {
        return res.status(400).json({ error: 'Phone number is required' });
    }

    try {
        const response = await axios.post('https://api.prembly.com/verification/phone', {
            number: phoneNumber
        }, {
            headers: {
                'app-id': process.env.PREMBLY_APP_ID || '',
                'x-api-key': process.env.PREMBLY_API_KEY || ''
            }
        });

        res.json(response.data);
    } catch (error) {
        console.error('Error verifying phone:', error.response ? error.response.data : error.message);
        res.status(error.response ? error.response.status : 500).json({
            error: 'Verification failed',
            details: error.response ? error.response.data : error.message
        });
    }
});

app.listen(PORT, () => {
    console.log(`Server is running on port ${PORT}`);
});

