            box-sizing: border-box;
        }
        button {
            padding: 10px 15px;
            background-color: #007bff;
            color: white;
            border: none;
            cursor: pointer;
        }
        button:hover {
            background-color: #0056b3;
        }
        #message {
            margin-top: 15px;
            font-weight: bold;
        }
    </style>
</head>
<body>
    <h1>Fintech Onboarding</h1>
    
    <div id="step-1" class="step active">
        <h2>Step 1: Phone Verification</h2>
        <form id="phone-form">
            <div class="form-group">
                <label for="phoneNumber">Phone Number:</label>
                <input type="text" id="phoneNumber" name="phoneNumber" required placeholder="Enter your phone number">
            </div>
            <button type="submit" id="verify-btn">Verify Phone</button>
        </form>
        <div id="message"></div>
    </div>

    <div id="step-2" class="step">
        <h2>Step 2: Face Liveliness Check</h2>
        <div id="widget-container"></div>
    </div>

    <script>
        document.getElementById('phone-form').addEventListener('submit', async (e) => {
            e.preventDefault();
            
            const phoneNumber = document.getElementById('phoneNumber').value;
            const messageDiv = document.getElementById('message');
            const verifyBtn = document.getElementById('verify-btn');
            
            messageDiv.textContent = 'Verifying...';
            messageDiv.style.color = 'black';
            verifyBtn.disabled = true;
            
            try {
                const response = await fetch('/api/verify-phone', {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json'
                    },
                    body: JSON.stringify({ phoneNumber })
                });
                
                const data = await response.json();
                
                if (response.ok) {
                    messageDiv.textContent = 'Verification successful!';
                    messageDiv.style.color = 'green';
                    
                    // Proceed to step 2 after a short delay
                    setTimeout(() => {
                        document.getElementById('step-1').classList.remove('active');
                        document.getElementById('step-2').classList.add('active');
                        
                        // Extract config_id from response if available, else use placeholder
                        const configId = data.config_id || 'placeholder_config_id';
                        
                        // Initialize the widget
                        initPremblyWidget(configId);
                    }, 1000);
                } else {
                    messageDiv.textContent = 'Verification failed: ' + (data.error || 'Unknown error');
                    messageDiv.style.color = 'red';
                    verifyBtn.disabled = false;
                }
            } catch (error) {
                messageDiv.textContent = 'Error: ' + error.message;
                messageDiv.style.color = 'red';
                verifyBtn.disabled = false;
            }
        });
        
        function initPremblyWidget(configId) {
            const container = document.getElementById('widget-container');
            
            // Display the Prembly Pass widget (<prembly-pass>)
            const widget = document.createElement('prembly-pass');
            widget.setAttribute('config_id', configId);
            widget.id = 'prembly-pass';
            
            container.appendChild(widget);
            
            // If there's a global script for Prembly Pass, we could also initialize it here
            if (typeof window.PremblyPass !== 'undefined') {
                try {
                    const prembly = new window.PremblyPass({
                        config_id: configId,
                        container: '#prembly-pass'
                    });
                    prembly.init();
                } catch (e) {
                    console.error('Error initializing PremblyPass via script:', e);
                }
            }
        }
    </script>
</body>
